webpackJsonp([32551418774257],{266:function(e,a){e.exports={data:{workHistory:{edges:[{node:{project:"Mortenson Kim",longName:"",intro:"MK is a creative agency with offices in Milwaukee and Indianapolis. They've marketing campaigns for a number of large clients, which have included Hoosier Lottery, Indianapolis Motor Speedway, and Roche, among others.",contribution:["As a Digital Developer at Mortenson Kim, my duties included building animated HTML5 banners, HTML emails, and Wordpress websites.","My biggest challenge was keeping up with the frantic pace of work, especially during the busy season when I was initially hired. To keep up with the demand, I setup a Webpack configuration, a custom plugin, and some boilerplate code to speed up the process. To further speed things up, I wrote a Photoshop script to speed up the collection of CSS styles."],links:[]}},{node:{project:"DIA2",longName:"Deep Insights Anytime Anywhere",intro:"DIA2 is a data visualization tool built for academics at Purdue University. This app allows users to search National Science Foundation records for trends in research, potential collaborators, and more. DIA2 itself is also funded by NSF, and the team has contributed to the body of research in fields including user research and data visualization.",contribution:["Working primarily as a front-end developer while pursuing my M.S., I worked all over the stack and collaborated with the design team. Most notably, I designed a minimalist login form and built the backend code for it.","Other contributions include implementation of a visual design overhaul, updates to tab creation and storage, and a demo functionality, allowing limited functionality for guest users.","Note: As of August 6th, 2018, I haven't been able to see the app, and don't know whether the tool is still being supported or whether the project is still being funded."],links:[{url:"https://dia2.org",str:"DIA2 landing page"}]}},{node:{project:"Soil Explorer / ISEE",longName:"Integrating Spatial Educational Experiences",intro:"Built Purdue University's Agronomy Department, ISEE is a web application and iPad app mapping soil data. It's used in Agronomy classes at Purdue, by researchers, and others interested in earth sciences.",contribution:["As an iOS developer, I worked on a barebones iPad app for displaying maps with soil data. Using ESRI's tools, I started with an app with a fixed image and baked in legend, and built a more interactive app.","As the only iOS developer, I faced a number of challenges, including UI, dynamically generated map legends, downloading, storage, and retrieval of additional maps, and interfacing with an ESRI API."],links:[{url:"https://itunes.apple.com/us/app/isee-integrating-spatial-educational/id996159565?mt=8",str:"ISEE App Store page"}]}}]}},pathContext:{}}}});
